var axios = require('axios')

// Recursive function to list all files and folders from Filen
const apiKey = $json.apiKey;
const baseFolderUUID = $json.baseFolderUUID;

async function listFilesRecursive(folderUUID, parentPath = "", depth = 0) {

  console.log(folderUUID + "_" + parentPath)

  if (depth > 20) return []; // Prevent infinite recursion

  const allItems = [];

  try {
    // Call Filen API to list folder content
    // const response = await request('https://gateway.filen.io/v3/dir/content', {
    //   method: 'POST',
    //   headers: {
    //     'Authorization': `Bearer ${apiKey}`,
    //     'Content-Type': 'application/json'
    //   },
    //   body: JSON.stringify({
    //     uuid: folderUUID
    //   })
    // });

    const response = await axios.post(
      'https://gateway.filen.io/v3/dir/content',
      {
        uuid: folderUUID
          },
      {
        headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
      },
                                                                                                                             timeout: 30000
      }
    );

    const data = response.data;

    if (!data.status) {
      console.error('Filen API error:', data.message);
      return allItems;
    }

    // Process files
    if (data.data.uploads && Array.isArray(data.data.uploads)) {
      for (const file of data.data.uploads) {
        // Note: In production, decrypt file.name with master key
        // For now, we'll use the encrypted name
        const fileName = file.name;

        allItems.push({
          type: 'file',
          uuid: file.uuid,
          name: fileName,
          path: parentPath ? `${parentPath}/${fileName}` : fileName,
          size: file.size || 0,
          encrypted_metadata: file.metadata
        });
      }
    }
    console.log(data.data.folders)
    // Recursively process folders
    if (data.data.folders && Array.isArray(data.data.folders)) {
      for (const folder of data.data.folders) {
        const folderName = folder.name;
        const newPath = parentPath ? `${parentPath}/${folderName}` : folderName;

        // Add folder to items
        allItems.push({
          type: 'folder',
          uuid: folder.uuid,
          name: folderName,
          path: newPath
        });

        // Recursively get files from subfolder
        const subItems = await listFilesRecursive(folder.uuid, newPath, depth + 1);
        allItems.push(...subItems);
      }
    }

  } catch (error) {
    console.error('Error listing files:', error.message);
  }

  return allItems;
}

// Start the recursive listing
const allItems = await listFilesRecursive(baseFolderUUID);
const allFiles = allItems.filter(item => item.type === 'file');

console.log(`Found ${allFiles.length} files to sync`);

return [{
  json: {
    files: allFiles,
    totalFiles: allFiles.length,
  }
}];

// Upload file in blocks to Lark
const uploadId = $input.fromNode('Lark - Prepare Upload').json?.data?.upload_id;
const blockSize = $input.fromNode('Lark - Prepare Upload').json?.data?.block_size || 4194304;
const blockNum = $input.fromNode('Lark - Prepare Upload').json?.data?.block_num || 1;
const fileBinary = $input.fromNode('Filen - Download File').json; // This will be the binary buffer
const larkToken = $env.LARK_TOKEN;
const fileName = $json.name;

if (!uploadId) {
  throw new Error('Upload ID not found from prepare response');
}

console.log(`Starting upload for ${fileName} with upload_id: ${uploadId}`);

try {
  for (let seq = 0; seq < blockNum; seq++) {
    const start = seq * blockSize;
    const end = Math.min(start + blockSize, fileBinary.length);
    const chunk = fileBinary.slice(start, end);

    console.log(`Uploading block ${seq + 1}/${blockNum}`);

    const response = await fetch(
      `https://open.larksuite.com/drive/v1/files/upload_part?upload_id=${uploadId}&seq=${seq}`,
      {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${larkToken}`,
          'Content-Type': 'application/octet-stream'
        },
        body: chunk
      }
    );

    if (!response.ok) {
      throw new Error(`Block ${seq} upload failed: ${response.statusText}`);
    }

    // Add delay between blocks to avoid rate limiting
    await new Promise(resolve => setTimeout(resolve, 500));
  }

  console.log(`All blocks uploaded for ${fileName}`);

  return [{
    json: {
      uploadId: uploadId,
      blockNum: blockNum,
      fileName: fileName,
      uploadStatus: 'blocks_uploaded'
    }
  }];

} catch (error) {
  throw new Error(`Failed to upload file blocks: ${error.message}`);
}

// Log successful sync
const fileName = $json.name;
const fileSize = $json.size;
const larkFileToken = $json.data?.file_token;

return [{
  json: {
    status: 'success',
    fileName: fileName,
    fileSize: fileSize,
    larkFileToken: larkFileToken,
    syncedAt: new Date().toISOString(),
    message: `✅ Successfully synced ${fileName} (${(fileSize / 1024 / 1024).toFixed(2)}MB)`
  }
}];

