const { createHash, pbkdf2Sync } = require('crypto');

// Helpers
async function hashPassword({ password }) {
  // Nếu có thuật toán hash riêng, thay thế tại đây; mặc định SHA-512
  return createHash('sha512')
    .update(Buffer.from(password, 'utf8'))
    .digest('hex');
}

async function hashFn({ input }) {
  return createHash('sha512')
    .update(Buffer.from(input, 'utf8'))
    .digest('hex');
}

async function deriveKeyFromPassword({
  password,
  salt,
  iterations,
  hash,      // 'sha512'
  bitLength, // 512
  returnHex  // true
}) {
  const keylenBytes = bitLength / 8;
  const derived = pbkdf2Sync(
    Buffer.from(password, 'utf8'),
    Buffer.from(salt, 'utf8'),
    iterations,
    keylenBytes,
    hash
  );
  return returnHex ? derived.toString('hex') : derived;
}

async function generatePasswordAndMasterKeyBasedOnAuthVersion({
  rawPassword,
  authVersion,
  salt
}) {
  if (authVersion === 1) {
    // DEPRECATED – backward compatibility
    const derivedPassword = await hashPassword({ password: rawPassword });
    const derivedMasterKeys = await hashFn({ input: rawPassword });
    return { derivedMasterKeys, derivedPassword };
  } else if (authVersion === 2) {
    const derivedKey = await deriveKeyFromPassword({
      password: rawPassword,
      salt,
      iterations: 200000,
      hash: 'sha512',
      bitLength: 512,
      returnHex: true
    });

    const half = derivedKey.length / 2;
    const derivedMasterKeys = derivedKey.substring(0, half);
    const derivedPasswordHalf = derivedKey.substring(half);

    const derivedPassword = createHash('sha512')
      .update(Buffer.from(derivedPasswordHalf, 'utf8'))
      .digest('hex');

    return { derivedMasterKeys, derivedPassword };
  } else {
    throw new Error(`Invalid authVersion: ${authVersion}`);
  }
}

