 * Giải mã metadata từ Filen
 * @param {string} encryptedMetadata - Chuỗi metadata được mã hóa (bắt đầu với "002")
 * @param {string} masterKey - Master key của người dùng (đã được derive từ password)
 * @returns {Promise<string>} - Chuỗi metadata được giải mã
 */
async function decryptMetadata(encryptedMetadata, masterKey) {
  try {
    // Bước 1: Kiểm tra định dạng - phải bắt đầu với "002"
    const version = encryptedMetadata.slice(0, 3);

    if (version !== "002") {
      throw new Error(`Invalid metadata version: ${version}. Expected "002"`);
    }

    // Bước 2: Transform key sử dụng PBKDF2
    // Sử dụng master key làm cả password và salt
    const transformedKey = await pbkdf2(
      masterKey,           // password
      masterKey,           // salt
      1,                   // iterations
      32,                  // keylen (256 bits = 32 bytes)
      'sha512'             // digest
    );

    // Bước 3: Tách các thành phần từ chuỗi mã hóa
    // Cấu trúc: "002" + nonce (12 ký tự) + base64(encrypted + authTag)
    const nonce = encryptedMetadata.slice(3, 15);      // Từ index 3 đến 15
    const encryptedBase64 = encryptedMetadata.slice(15); // Từ index 15 trở đi

    // Chuyển đổi nonce từ UTF-8 string thành Buffer
    const nonceBuffer = Buffer.from(nonce, 'utf-8');

    // Giải mã base64 để lấy encrypted data + auth tag
    const encrypted = Buffer.from(encryptedBase64, 'base64');

    // Auth tag luôn là 16 bytes cuối cùng
    const authTag = encrypted.subarray(-16);
    const cipherText = encrypted.subarray(0, encrypted.byteLength - 16);

    // Bước 4: Giải mã sử dụng AES-256-GCM
    const decipher = crypto.createDecipheriv('aes-256-gcm', transformedKey, nonceBuffer);
    decipher.setAuthTag(authTag);

    const decrypted = Buffer.concat([
      decipher.update(cipherText),
      decipher.final()
    ]).toString('utf-8');

    return decrypted;
  } catch (error) {
    throw new Error(`Metadata decryption failed: ${error.message}`);
  }
}

/**
