 * @param {string} encryptedFileName - Tên file được mã hóa
 * @param {string} masterKey - Master key của người dùng
 * @returns {Promise<string>} - Tên file gốc
 */
async function decryptFileName(encryptedFileName, masterKey) {
  try {
    const decrypted = await decryptMetadata(encryptedFileName, masterKey);

    // Thường tên file được lưu dưới dạng JSON string
    // Cố gắng parse nếu là JSON, nếu không trả về chuỗi thô
    try {
      const parsed = JSON.parse(decrypted);
      return typeof parsed === 'string' ? parsed : JSON.stringify(parsed);
    } catch {
      return decrypted;
    }
  } catch (error) {
    throw new Error(`File name decryption failed: ${error.message}`);
  }
}

/**
 * Hàm tiện ích: Giải mã metadata với nhiều master keys
 * Dùng khi bạn có danh sách các master key (hiện tại và cũ)
 * @param {string} encryptedMetadata - Metadata được mã hóa
 * @param {string[]} masterKeys - Danh sách master keys
 * @returns {Promise<string|null>} - Metadata được giải mã hoặc null nếu không tìm thấy
 */
async function decryptMetadataWithMultipleKeys(encryptedMetadata, masterKeys) {
  // Duyệt từ cuối về đầu để tối ưu hiệu suất
  for (let i = masterKeys.length - 1; i >= 0; i--) {
    try {
      const decrypted = await decryptMetadata(encryptedMetadata, masterKeys[i]);
      return decrypted;
    } catch (error) {
      // Tiếp tục thử key tiếp theo
      continue;
    }
  }

  throw new Error('Failed to decrypt metadata with any available master key');
}

